export function Navigate({
  to,
  replace,
  state,
  relative,
}: NavigateProps): null {
  invariant(
    useInRouterContext(),
    // TODO: This error is probably because they somehow have 2 versions of
    // the router loaded. We can help them understand how to avoid that.
    `<Navigate> may be used only in the context of a <Router> component.`,
  );

  let { static: isStatic } = React.useContext(NavigationContext);

  warning(
    !isStatic,
    `<Navigate> must not be used on the initial render in a <StaticRouter>. ` +
      `This is a no-op, but you should modify your code so the <Navigate> is ` +
      `only ever rendered in response to some user interaction or state change.`,
  );

  let { matches } = React.useContext(RouteContext);
  let { pathname: locationPathname } = useLocation();
  let navigate = useNavigate();

  // Resolve the path outside of the effect so that when effects run twice in
  // StrictMode they navigate to the same place
  let path = resolveTo(
    to,
    getResolveToMatches(matches),
    locationPathname,
    relative === "path",
  );
  let jsonPath = JSON.stringify(path);

  React.useEffect(() => {
    navigate(JSON.parse(jsonPath), { replace, state, relative });
  }, [navigate, jsonPath, relative, replace, state]);

  return null;
}

export function MemoryRouter({
  basename,
  children,
  initialEntries,
  initialIndex,
  useTransitions,
}: MemoryRouterProps): React.ReactElement {
  let historyRef = React.useRef<MemoryHistory>();
  if (historyRef.current == null) {
    historyRef.current = createMemoryHistory({
      initialEntries,
      initialIndex,
      v5Compat: true,
    });
  }

  let history = historyRef.current;
  let [state, setStateImpl] = React.useState({
    action: history.action,
    location: history.location,
  });
  let setState = React.useCallback(
    (newState: { action: NavigationType; location: Location }) => {
      if (useTransitions === false) {
        setStateImpl(newState);
      } else {
        React.startTransition(() => setStateImpl(newState));
      }
    },
    [useTransitions],
  );

  React.useLayoutEffect(() => history.listen(setState), [history, setState]);

  return (
    <Router
      basename={basename}
      children={children}
      location={state.location}
      navigationType={state.action}
      navigator={history}
      useTransitions={useTransitions}
    />
  );
}

export function useExitAnimation(ref: RefObject<HTMLElement | null>, isOpen: boolean): boolean {
  let [exitState, setExitState] = useState<'closed' | 'open' | 'exiting'>(
    isOpen ? 'open' : 'closed'
  );

  switch (exitState) {
    case 'open':
      // If isOpen becomes false, set the state to exiting.
      if (!isOpen) {
        setExitState('exiting');
      }
      break;
    case 'closed':
    case 'exiting':
      // If we are exiting and isOpen becomes true, the animation was interrupted.
      // Reset the state to open.
      if (isOpen) {
        setExitState('open');
      }
      break;
  }

  let isExiting = exitState === 'exiting';
  useAnimation(
    ref,
    isExiting,
    useCallback(() => {
      // Set the state to closed, which will cause the element to be unmounted.
      setExitState(state => (state === 'exiting' ? 'closed' : state));
    }, [])
  );

  return isExiting;
}

export function useDescription(description?: string): AriaLabelingProps {
  let [id, setId] = useState<string | undefined>();

  useLayoutEffect(() => {
    if (!description) {
      return;
    }

    let desc = descriptionNodes.get(description);
    if (!desc) {
      let id = `react-aria-description-${descriptionId++}`;
      setId(id);

      let node = document.createElement('div');
      node.id = id;
      node.style.display = 'none';
      node.textContent = description;
      document.body.appendChild(node);
      desc = {refCount: 0, element: node};
      descriptionNodes.set(description, desc);
    } else {
      setId(desc.element.id);
    }

    desc.refCount++;
    return () => {
      if (desc && --desc.refCount === 0) {
        desc.element.remove();
        descriptionNodes.delete(description);
      }
    };
  }, [description]);

  return {
    'aria-describedby': description ? id : undefined
  };
}

export function useGlobalListeners(): GlobalListeners {
  let globalListeners = useRef(new Map());
  let addGlobalListener = useCallback((eventTarget, type, listener, options) => {
    // Make sure we remove the listener after it is called with the `once` option.
    let fn = options?.once
      ? (...args) => {
          globalListeners.current.delete(listener);
          listener(...args);
        }
      : listener;
    globalListeners.current.set(listener, {type, eventTarget, fn, options});
    eventTarget.addEventListener(type, fn, options);
  }, []);
  let removeGlobalListener = useCallback((eventTarget, type, listener, options) => {
    let fn = globalListeners.current.get(listener)?.fn || listener;
    eventTarget.removeEventListener(type, fn, options);
    globalListeners.current.delete(listener);
  }, []);
  let removeAllGlobalListeners = useCallback(() => {
    globalListeners.current.forEach((value, key) => {
      removeGlobalListener(value.eventTarget, value.type, key, value.options);
    });
  }, [removeGlobalListener]);

  useEffect(() => {
    return removeAllGlobalListeners;
  }, [removeAllGlobalListeners]);

  return {addGlobalListener, removeGlobalListener, removeAllGlobalListeners};
}

export function Autocomplete<T>(props: AutocompleteProps<T>): JSX.Element {
  let ctx = useSlottedContext(AutocompleteContext, props.slot);
  props = mergeProps(ctx, props);
  let {filter, disableAutoFocusFirst} = props;
  let state = useAutocompleteState(props);
  let inputRef = useRef<HTMLInputElement | null>(null);
  let collectionRef = useRef<HTMLElement>(null);
  let {
    inputProps,
    collectionProps,
    collectionRef: mergedCollectionRef,
    filter: filterFn
  } = useAutocomplete(
    {
      ...removeDataAttributes(props),
      filter,
      disableAutoFocusFirst,
      inputRef,
      collectionRef
    },
    state
  );

  return (
    <Provider
      values={[
        [AutocompleteStateContext, state],
        [
          FieldInputContext,
          {
            ...inputProps,
            ref: inputRef
          }
        ],
        [
          SelectableCollectionContext,
          {
            ...collectionProps,
            filter: filterFn,
            ref: mergedCollectionRef
          }
        ]
      ]}>
      {props.children}
    </Provider>
  );
}

function ColorChannelField(props: ColorChannelFieldProps) {
  let {locale} = useLocale();
  let state = useColorChannelFieldState({
    ...props,
    locale
  });

  let inputRef = useRef<HTMLInputElement>(null);
  let [labelRef, label] = useSlot(!props['aria-label'] && !props['aria-labelledby']);
  let {labelProps, inputProps, descriptionProps, errorMessageProps, ...validation} =
    useColorChannelField(
      {
        ...removeDataAttributes(props),
        label,
        validationBehavior: props.validationBehavior ?? 'native'
      },
      state,
      inputRef
    );

  return (
    <>
      {useChildren(
        props,
        state,
        props.forwardedRef,
        inputProps,
        inputRef,
        labelProps,
        labelRef,
        descriptionProps,
        errorMessageProps,
        validation
      )}
      {props.name && (
        <input
          type="hidden"
          name={props.name}
          form={props.form}
          value={isNaN(state.numberValue) ? '' : state.numberValue}
        />
      )}
    </>
  );
}

export function MenuTrigger(props: MenuTriggerProps): JSX.Element | null {
  let state = useMenuTriggerState(props);
  let ref = useRef<HTMLButtonElement>(null);
  let {menuTriggerProps, menuProps} = useMenuTrigger(
    {
      ...props,
      type: 'menu'
    },
    state,
    ref
  );
  let scrollRef = useRef(null);

  // If within a collection (e.g. Tabs), render nothing.
  // Not using createHideableComponent for this because that also creates a forwardRef.
  let isHidden = useIsHidden();
  if (isHidden) {
    return null;
  }

  return (
    <Provider
      values={[
        [MenuContext, {...menuProps, ref: scrollRef}],
        [OverlayTriggerStateContext, state],
        [RootMenuTriggerStateContext, state],
        [
          PopoverContext,
          {
            trigger: 'MenuTrigger',
            triggerRef: ref,
            scrollRef,
            placement: 'bottom start',
            'aria-labelledby': menuProps['aria-labelledby']
          }
        ]
      ]}>
      <PressResponder {...menuTriggerProps} ref={ref} isPressed={state.isOpen}>
        {props.children}
      </PressResponder>
    </Provider>
  );
}

function Meter(
  props: MeterProps,
  ref: ForwardedRef<HTMLDivElement>
) {
  [props, ref] = useContextProps(props, ref, MeterContext);
  let {value = 0, minValue = 0, maxValue = 100} = props;
  value = clamp(value, minValue, maxValue);

  let [labelRef, label] = useSlot(!props['aria-label'] && !props['aria-labelledby']);
  let {meterProps, labelProps} = useMeter({...props, label});

  // Calculate the width of the progress bar as a percentage
  let percentage = ((value - minValue) / (maxValue - minValue)) * 100;

  let renderProps = useRenderProps({
    ...props,
    defaultClassName: 'react-aria-Meter',
    values: {
      percentage,
      valueText: meterProps['aria-valuetext']
    }
  });

  let DOMProps = filterDOMProps(props, {global: true});

  return (
    <dom.div
      {...mergeProps(DOMProps, renderProps, meterProps)}
      ref={ref}
      slot={props.slot || undefined}>
      <LabelContext.Provider value={{...labelProps, ref: labelRef, elementType: 'span'}}>
        {renderProps.children}
      </LabelContext.Provider>
    </dom.div>
  );
}

function OverlayArrow(
  props: OverlayArrowProps,
  ref: ForwardedRef<HTMLDivElement>
) {
  [props, ref] = useContextProps(props, ref, OverlayArrowContext);
  let placement = (props as OverlayArrowContextValue).placement;
  let style: CSSProperties = {
    position: 'absolute',
    transform:
      placement === 'top' || placement === 'bottom' ? 'translateX(-50%)' : 'translateY(-50%)'
  };
  if (placement != null) {
    style[placement] = '100%';
  }

  let renderProps = useRenderProps({
    ...props,
    defaultClassName: 'react-aria-OverlayArrow',
    values: {
      placement
    }
  });
  // remove undefined values from renderProps.style object so that it can be
  // spread merged with the other style object
  if (renderProps.style) {
    Object.keys(renderProps.style).forEach(
      key => renderProps.style![key] === undefined && delete renderProps.style![key]
    );
  }

  let DOMProps = filterDOMProps(props);

  return (
    <dom.div
      {...DOMProps}
      {...renderProps}
      style={{
        ...style,
        ...renderProps.style
      }}
      ref={ref}
      data-placement={placement}
    />
  );
}

function Popover(
  props: PopoverProps,
  ref: ForwardedRef<HTMLElement>
) {
  [props, ref] = useContextProps(props, ref, PopoverContext);
  let contextState = useContext(OverlayTriggerStateContext);
  let localState = useOverlayTriggerState(props);
  let state =
    props.isOpen != null || props.defaultOpen != null || !contextState ? localState : contextState;
  let isExiting = useExitAnimation(ref, state.isOpen) || props.isExiting || false;
  let isHidden = useIsHidden();
  let {direction} = useLocale();

  // If we are in a hidden tree, we still need to preserve our children.
  if (isHidden) {
    let children = props.children;
    if (typeof children === 'function') {
      children = children({
        trigger: props.trigger || null,
        placement: 'bottom',
        isEntering: false,
        isExiting: false,
        defaultChildren: null
      });
    }

    return <>{children}</>;
  }

  if (state && !state.isOpen && !isExiting) {
    return null;
  }

  return (
    <PopoverInner
      {...props}
      triggerRef={props.triggerRef!}
      state={state}
      popoverRef={ref}
      isExiting={isExiting}
      dir={direction}
    />
  );
}

function ProgressBar(
  props: ProgressBarProps,
  ref: ForwardedRef<HTMLDivElement>
) {
  [props, ref] = useContextProps(props, ref, ProgressBarContext);
  let {value = 0, minValue = 0, maxValue = 100, isIndeterminate = false} = props;
  value = clamp(value, minValue, maxValue);

  let [labelRef, label] = useSlot(!props['aria-label'] && !props['aria-labelledby']);
  let {progressBarProps, labelProps} = useProgressBar({...props, label});

  // Calculate the width of the progress bar as a percentage
  let percentage = isIndeterminate ? undefined : ((value - minValue) / (maxValue - minValue)) * 100;

  let renderProps = useRenderProps({
    ...props,
    defaultClassName: 'react-aria-ProgressBar',
    values: {
      percentage,
      valueText: progressBarProps['aria-valuetext'],
      isIndeterminate
    }
  });

  let DOMProps = filterDOMProps(props, {global: true});

  return (
    <dom.div
      {...mergeProps(DOMProps, renderProps, progressBarProps)}
      ref={ref}
      slot={props.slot || undefined}>
      <LabelContext.Provider value={{...labelProps, ref: labelRef, elementType: 'span'}}>
        {renderProps.children}
      </LabelContext.Provider>
    </dom.div>
  );
}

function Table(
  props: TableProps,
  ref: ForwardedRef<HTMLTableElement | HTMLDivElement>
) {
  [props, ref] = useContextProps(props, ref, TableContext);

  // Separate selection state so we have access to it from collection components via useTableOptions.
  let selectionState = useMultipleSelectionState(props);
  let {selectionBehavior, selectionMode, disallowEmptySelection} = selectionState;
  let hasDragHooks = !!props.dragAndDropHooks?.useDraggableCollectionState;
  let ctx = useMemo(
    () => ({
      selectionBehavior: selectionMode === 'none' ? null : selectionBehavior,
      selectionMode,
      disallowEmptySelection,
      allowsDragging: hasDragHooks
    }),
    [selectionBehavior, selectionMode, disallowEmptySelection, hasDragHooks]
  );

  let content = (
    <TableOptionsContext.Provider value={ctx}>
      <Collection {...props} />
    </TableOptionsContext.Provider>
  );

  return (
    <CollectionBuilder content={content} createCollection={() => new TableCollection<any>()}>
      {collection => (
        <TableInner
          props={props}
          forwardedRef={ref as any}
          selectionState={selectionState}
          collection={collection}
        />
      )}
    </CollectionBuilder>
  );
}

function TableHeaderRow({item}: {item: GridNode<any>}) {
  let ref = useRef<HTMLTableRowElement>(null);
  let state = useContext(TableStateContext)!;
  let {isVirtualized, CollectionBranch} = useContext(CollectionRendererContext);
  let {rowProps} = useTableHeaderRow({node: item, isVirtualized}, state, ref);
  let {checkboxProps} = useTableSelectAllCheckbox(state);

  return (
    <TableHeaderRowElementType {...rowProps} ref={ref}>
      <Provider
        values={[
          [
            CheckboxContext,
            {
              slots: {
                selection: checkboxProps
              }
            }
          ],
          [
            CheckboxFieldContext,
            {
              slots: {
                selection: checkboxProps
              }
            }
          ]
        ]}>
        <CollectionBranch collection={state.collection} parent={item} />
      </Provider>
    </TableHeaderRowElementType>
  );
}

function TabListInner<T>({props, forwardedRef: ref}: TabListInnerProps<T>) {
  let state = useContext(TabListStateContext)!;
  let {CollectionRoot} = useContext(CollectionRendererContext);
  let {orientation = 'horizontal', keyboardActivation = 'automatic'} =
    useSlottedContext(TabsContext)!;
  let objectRef = useObjectRef(ref);

  let {tabListProps} = useTabList(
    {
      ...props,
      orientation,
      keyboardActivation
    },
    state,
    objectRef
  );

  let renderProps = useRenderProps({
    ...props,
    children: null,
    defaultClassName: 'react-aria-TabList',
    values: {
      orientation,
      state
    }
  });

  let DOMProps = filterDOMProps(props, {global: true});
  delete DOMProps.id;

  return (
    <dom.div
      {...mergeProps(DOMProps, renderProps, tabListProps)}
      ref={objectRef}
      data-orientation={orientation || undefined}>
      <SharedElementTransition>
        <CollectionRoot
          collection={state.collection}
          persistedKeys={usePersistedKeys(state.selectionManager.focusedKey)}
        />
      </SharedElementTransition>
    </dom.div>
  );
}

export function useToggleButtonGroupItem(
  props: AriaToggleButtonGroupItemOptions<ElementType>,
  state: ToggleGroupState,
  ref: RefObject<any>
): ToggleButtonAria<HTMLAttributes<any>> {
  let toggleState: ToggleState = {
    isSelected: state.selectedKeys.has(props.id),
    defaultSelected: false,
    setSelected(isSelected) {
      state.setSelected(props.id, isSelected);
    },
    toggle() {
      state.toggleKey(props.id);
    }
  };

  let {isPressed, isSelected, isDisabled, buttonProps} = useToggleButton(
    {
      ...props,
      id: undefined,
      isDisabled: props.isDisabled || state.isDisabled
    },
    toggleState,
    ref
  );
  if (state.selectionMode === 'single') {
    buttonProps.role = 'radio';
    buttonProps['aria-checked'] = toggleState.isSelected;
    delete buttonProps['aria-pressed'];
  }

  return {
    isPressed,
    isSelected,
    isDisabled,
    buttonProps
  };
}

export function createLeafComponent<P extends object, E extends Element>(
  CollectionNodeClass: CollectionNodeClass<any> | string,
  render: (props: P, ref: ForwardedRef<E>, node?: any) => ReactElement | null
): (props: P & React.RefAttributes<any>) => ReactElement | null {
  let Component = ({node}) => render(node.props, node.props.ref, node);
  let Result = (forwardRef as forwardRefType)((props: P, ref: ForwardedRef<E>) => {
    let focusableProps = useContext(FocusableContext);
    let isShallow = useContext(ShallowRenderContext);
    if (!isShallow) {
      if (render.length >= 3) {
        throw new Error(render.name + ' cannot be rendered outside a collection.');
      }
      return render(props, ref);
    }

    return useSSRCollectionNode(
      CollectionNodeClass,
      props,
      ref,
      'children' in props ? props.children : null,
      null,
      node => (
        // Forward FocusableContext to real DOM tree so tooltips work.
        <FocusableContext.Provider value={focusableProps}>
          <Component node={node} />
        </FocusableContext.Provider>
      )
    );
  });
  // @ts-ignore
  Result.displayName = render.name;
  return Result;
}

export function useId(defaultId?: string): string {
  let [value, setValue] = useState(defaultId);
  let nextId = useRef(null);

  let res = useSSRSafeId(value);
  let cleanupRef = useRef(null);

  if (registry) {
    registry.register(cleanupRef, res);
  }

  if (canUseDOM) {
    const cacheIdRef = idsUpdaterMap.get(res);
    if (cacheIdRef && !cacheIdRef.includes(nextId)) {
      cacheIdRef.push(nextId);
    } else {
      idsUpdaterMap.set(res, [nextId]);
    }
  }

  useLayoutEffect(() => {
    let r = res;
    return () => {
      // In Suspense, the cleanup function may be not called
      // when it is though, also remove it from the finalization registry.
      if (registry) {
        registry.unregister(cleanupRef);
      }
      idsUpdaterMap.delete(r);
    };
  }, [res]);

  // This cannot cause an infinite loop because the ref is always cleaned up.
  // eslint-disable-next-line
  useEffect(() => {
    let newId = nextId.current;
    if (newId) {
      setValue(newId);
    }

    return () => {
      if (newId) {
        nextId.current = null;
      }
    };
  });

  return res;
}

export function finishQueueingConcurrentUpdates(): void {
  const endIndex = concurrentQueuesIndex;
  concurrentQueuesIndex = 0;

  concurrentlyUpdatedLanes = NoLanes;

  let i = 0;
  while (i < endIndex) {
    const fiber: Fiber = concurrentQueues[i];
    concurrentQueues[i++] = null;
    const queue: ConcurrentQueue = concurrentQueues[i];
    concurrentQueues[i++] = null;
    const update: ConcurrentUpdate = concurrentQueues[i];
    concurrentQueues[i++] = null;
    const lane: Lane = concurrentQueues[i];
    concurrentQueues[i++] = null;

    // $FlowFixMe[invalid-compare]
    if (queue !== null && update !== null) {
      const pending = queue.pending;
      if (pending === null) {
        // This is the first update. Create a circular list.
        update.next = update;
      } else {
        update.next = pending.next;
        pending.next = update;
      }
      queue.pending = update;
    }

    if (lane !== NoLane) {
      markUpdateLaneFromFiberToRoot(fiber, update, lane);
    }
  }
}

import type { Field } from '../types';
import isCheckBox from '../utils/isCheckBoxInput';
import isFileInput from '../utils/isFileInput';
import isMultipleSelect from '../utils/isMultipleSelect';
import isRadioInput from '../utils/isRadioInput';
import isUndefined from '../utils/isUndefined';

import getCheckboxValue from './getCheckboxValue';
import getFieldValueAs from './getFieldValueAs';
import getRadioValue from './getRadioValue';

export default function getFieldValue(_f: Field['_f']) {
  const ref = _f.ref;

  if (isFileInput(ref)) {
    return ref.files;
  }

  if (isRadioInput(ref)) {
    return getRadioValue(_f.refs).value;
  }

  if (isMultipleSelect(ref)) {
    return [...ref.selectedOptions].map(({ value }) => value);
  }

  if (isCheckBox(ref)) {
    return getCheckboxValue(_f.refs).value;
  }

  return getFieldValueAs(isUndefined(ref.value) ? _f.ref.value : ref.value, _f);
}

export function getNormalizedPath(
  request: Request,
  basename: string | undefined,
  future: FutureConfig | null,
): Path {
  basename = basename || "/";

  let url = new URL(request.url);
  let pathname = url.pathname;

  // Strip .data suffix
  if (future?.v8_trailingSlashAwareDataRequests) {
    if (pathname.endsWith("/_.data")) {
      // Handle trailing slash URLs: /about/_.data -> /about/
      pathname = pathname.replace(/_\.data$/, "");
    } else {
      pathname = pathname.replace(/\.data$/, "");
    }
  } else {
    if (stripBasename(pathname, basename) === "/_root.data") {
      pathname = basename;
    } else if (pathname.endsWith(".data")) {
      pathname = pathname.replace(/\.data$/, "");
    }

    if (stripBasename(pathname, basename) !== "/" && pathname.endsWith("/")) {
      pathname = pathname.slice(0, -1);
    }
  }

  // Strip _routes param
  let searchParams = new URLSearchParams(url.search);
  searchParams.delete("_routes");
  let search = searchParams.toString();
  if (search) {
    search = `?${search}`;
  }

  // Don't touch index params here - they're needed for router matching and are
  // stripped when creating the loader/action args

  return {
    pathname,
    search,
    // No hashes on the server
    hash: "",
  };
}

function mergeTheme(theme: ThemeArgument, outerTheme?: DefaultTheme | undefined): DefaultTheme {
  if (!theme) {
    throw styledError(14);
  }

  if (isFunction(theme)) {
    const themeFn = theme as ThemeFn;
    const mergedTheme = themeFn(outerTheme);

    if (
      __DEV__ &&
      (mergedTheme === null || Array.isArray(mergedTheme) || typeof mergedTheme !== 'object')
    ) {
      throw styledError(7);
    }

    return mergedTheme;
  }

  if (Array.isArray(theme) || typeof theme !== 'object') {
    throw styledError(8);
  }

  // Native uses deep-merge so createTheme() sentinel values from the
  // outer theme propagate through unless specifically overridden. The
  // web path keeps its original shallow-spread because the CSS cascade
  // handles per-variable inheritance.
  if (__NATIVE__) {
    return outerTheme ? deepMergeTheme(outerTheme, theme) : theme;
  }
  return outerTheme ? { ...outerTheme, ...theme } : theme;
}

function useCollectionRender(
  collection: ICollection<Node<unknown>>,
  parent: Node<unknown> | null,
  renderDropIndicator?: (target: ItemDropTarget) => ReactNode
) {
  return useCachedChildren({
    items: parent ? collection.getChildren!(parent.key) : collection,
    dependencies: [renderDropIndicator],
    children(node) {
      // Return a empty fragment since we don't want to render the content twice
      // If we don't skip the content node here, we end up rendering them twice in a Tree since we also render the content node in TreeItem
      if (node.type === 'content') {
        return <></>;
      }

      let rendered = node.render!(node);
      if (!renderDropIndicator || node.type !== 'item') {
        return rendered;
      }

      return (
        <>
          {renderDropIndicator({type: 'item', key: node.key, dropPosition: 'before'})}
          {rendered}
          {renderAfterDropIndicators(collection, node, renderDropIndicator)}
        </>
      );
    }
  });
}

private updateColumns(isSSR: boolean) {
  if (!this.columnsDirty) {
    return;
  }

  this.rowHeaderColumnKeys = new Set();
  this.columns = [];
  let columnKeyMap = new Map();
  let visit = (node: Node<T>) => {
    switch (node.type) {
      case 'column':
        columnKeyMap.set(node.key, node);
        if (!node.hasChildNodes) {
          node.index = this.columns.length;
          this.columns.push(node);

          if (node.props.isRowHeader) {
            this.rowHeaderColumnKeys.add(node.key);
          }
        }
        break;
    }
    for (let child of this.getChildren(node.key)) {
      visit(child);
    }
  };

  for (let node of this.getChildren(this.head.key)) {
    visit(node);
  }

  this.headerRows = buildHeaderRows(columnKeyMap, this.columns);
  this.columnsDirty = false;
  if (this.rowHeaderColumnKeys.size === 0 && this.columns.length > 0 && !isSSR) {
    throw new Error(
      'A table must have at least one Column with the isRowHeader prop set to true'
    );
  }
}

export function useColorSwatch(props: AriaColorSwatchProps): ColorSwatchAria {
  let {color: value, colorName} = props;
  let nonNullValue = value || '#fff0';
  let color = useMemo(
    () => (typeof nonNullValue === 'string' ? parseColor(nonNullValue) : nonNullValue),
    [nonNullValue]
  );
  let {locale} = useLocale();
  let DOMProps = filterDOMProps(props, {labelable: true});
  let stringFormatter = useLocalizedStringFormatter(intlMessages, '@react-aria/color');
  let id = useId(props.id);

  if (!colorName) {
    colorName =
      color.getChannelValue('alpha') === 0
        ? stringFormatter.format('transparent')
        : color.getColorName(locale);
  }

  return {
    colorSwatchProps: {
      ...DOMProps,
      role: 'img',
      'aria-roledescription': stringFormatter.format('colorSwatch'),
      'aria-label': [colorName, props['aria-label'] || ''].filter(Boolean).join(', '),
      'aria-labelledby': props['aria-labelledby'] ? `${id} ${props['aria-labelledby']}` : undefined,
      id,
      style: {
        backgroundColor: color.toString('css'),
        // @ts-ignore
        forcedColorAdjust: 'none'
      }
    },
    color: color || null
  };
}

export function lazy<T>(
  ctor: () => Thenable<{default: T, ...}>,
): LazyComponent<T, Payload<T>> {
  const payload: Payload<T> = {
    // We use these fields to store the result.
    _status: Uninitialized,
    _result: ctor,
  };

  const lazyType: LazyComponent<T, Payload<T>> = {
    $$typeof: REACT_LAZY_TYPE,
    _payload: payload,
    _init: lazyInitializer,
  };

  if (__DEV__ && enableAsyncDebugInfo) {
    // TODO: We should really track the owner here but currently ReactIOInfo
    // can only contain ReactComponentInfo and not a Fiber. It's unusual to
    // create a lazy inside an owner though since they should be in module scope.
    const owner = null;
    const ioInfo: ReactIOInfo = {
      name: 'lazy',
      start: -1,
      end: -1,
      value: null,
      owner: owner,
      debugStack: new Error('react-stack-top-frame'),
      // eslint-disable-next-line react-internal/no-production-logging
      debugTask: console.createTask ? console.createTask('lazy()') : null,
    };
    payload._ioInfo = ioInfo;
    // Add debug info to the lazy, but this doesn't have an await stack yet.
    // That will be inferred by later usage.
    lazyType._debugInfo = [{awaited: ioInfo}];
  }

  return lazyType;
}

import isUndefined from '../utils/isUndefined';

type CheckboxFieldResult = {
  isValid: boolean;
  value: string | string[] | boolean | undefined;
};

const defaultResult: CheckboxFieldResult = {
  value: false,
  isValid: false,
};

const validResult = { value: true, isValid: true };

export default (options?: HTMLInputElement[]): CheckboxFieldResult => {
  if (Array.isArray(options)) {
    if (options.length > 1) {
      const values = options
        .filter((option) => option && option.checked && !option.disabled)
        .map((option) => option.value);
      return { value: values, isValid: !!values.length };
    }

    return options[0].checked && !options[0].disabled
      ? // @ts-expect-error expected to work in the browser
        options[0].attributes && !isUndefined(options[0].attributes.value)
        ? isUndefined(options[0].value) || options[0].value === ''
          ? validResult
          : { value: options[0].value, isValid: true }
        : validResult
      : defaultResult;
  }

  return defaultResult;
};

const setState = useCallback((payload: Partial<S>) => {
    let shouldRerender = false

    const currentState = stateRef.current
    for (const key in payload) {
      if (Object.prototype.hasOwnProperty.call(payload, key)) {
        const k = key as keyof S

        // If the property has changed, update the state and mark rerender as
        // needed.
        if (currentState[k] !== payload[k]) {
          currentState[k] = payload[k]!

          // If the property is accessed by the component, a rerender should be
          // triggered.
          if (stateDependenciesRef.current[k]) {
            shouldRerender = true
          }
        }
      }
    }

    if (shouldRerender && !unmountedRef.current) {
      rerender({})
    }
  }, [])

  useIsomorphicLayoutEffect(() => {
    unmountedRef.current = false
    return () => {
      unmountedRef.current = true
    }
  })

  return [stateRef, stateDependenciesRef.current, setState]

function renderWrapper(
  parent: View | null,
  reusableView: View,
  renderDropIndicator?: (target: ItemDropTarget) => ReactNode
): ReactNode {
  let rendered = (
    <VirtualizerItem
      key={reusableView.key}
      layoutInfo={reusableView.layoutInfo!}
      virtualizer={reusableView.virtualizer}
      parent={parent?.layoutInfo}>
      {reusableView.rendered}
    </VirtualizerItem>
  );

  let {collection, layout} = reusableView.virtualizer;
  let node = reusableView.content;
  if (node?.type === 'item' && renderDropIndicator && layout.getDropTargetLayoutInfo) {
    rendered = (
      <React.Fragment key={reusableView.key}>
        {renderDropIndicatorWrapper(
          parent,
          reusableView,
          {type: 'item', key: reusableView.content!.key, dropPosition: 'before'},
          renderDropIndicator
        )}
        {rendered}
        {renderAfterDropIndicators(collection, node, target =>
          renderDropIndicatorWrapper(parent, reusableView, target, renderDropIndicator)
        )}
      </React.Fragment>
    );
  }

  return rendered;
}

const eventRegex = /^on[A-Z]/

export function mergeProps<T extends Props>(
  ...args: T[]
): UnionToIntersection<TupleTypes<T[]>> {
  let result: Props = {}

  for (let props of args) {
    for (let key in result) {
      if (
        eventRegex.test(key) &&
        typeof result[key] === "function" &&
        typeof props[key] === "function"
      ) {
        result[key] = callAll(result[key], props[key])
        continue
      }

      if (key === "className" || key === "class") {
        result[key] = clsx(result[key], props[key])
        continue
      }

      if (key === "style") {
        result[key] = Object.assign({}, result[key] ?? {}, props[key] ?? {})
        continue
      }

      result[key] = props[key] !== undefined ? props[key] : result[key]
    }

    // Add props from b that are not in a
    for (let key in props) {
      if (result[key] === undefined) {
        result[key] = props[key]
      }
    }
  }

  return result as any
}

export function throwIfPotentialCSRFAttack(
  headers: Headers,
  allowedActionOrigins: string[] | undefined,
) {
  let originHeader = headers.get("origin");
  let originDomain: string | null = null;

  try {
    originDomain =
      typeof originHeader === "string" && originHeader !== "null"
        ? new URL(originHeader).host
        : originHeader;
  } catch {
    throw new Error(
      `\`origin\` header is not a valid URL. Aborting the action.`,
    );
  }
  let host = parseHostHeader(headers);

  if (originDomain && (!host || originDomain !== host.value)) {
    if (!isAllowedOrigin(originDomain, allowedActionOrigins)) {
      if (host) {
        // This seems to be an CSRF attack. We should not proceed with the action.
        throw new Error(
          `${host.type} header does not match \`origin\` header from a forwarded ` +
            `action request. Aborting the action.`,
        );
      } else {
        // This is an attack. We should not proceed with the action.
        throw new Error(
          "`x-forwarded-host` or `host` headers are not provided. One of these " +
            "is needed to compare the `origin` header from a forwarded action " +
            "request. Aborting the action.",
        );
      }
    }
  }
}

updateCollection(): void {
  // First, remove disconnected nodes and update the indices of dirty element children.
  for (let element of this.dirtyNodes) {
    if (element instanceof ElementNode && (!element.isConnected || element.isHidden)) {
      this.removeNode(element);
    } else {
      element.updateChildIndices();
    }
  }

  // Next, update dirty collection nodes.
  for (let element of this.dirtyNodes) {
    if (element instanceof ElementNode) {
      if (element.isConnected && !element.isHidden) {
        element.updateNode();
        this.addNode(element);
      }

      if (element.node) {
        this.dirtyNodes.delete(element);
      }

      element.isMutated = false;
    } else {
      this.dirtyNodes.delete(element);
    }
  }

  // Finally, update the collection.
  if (this.nextCollection) {
    this.nextCollection.commit(
      this.firstVisibleChild?.node?.key ?? null,
      this.lastVisibleChild?.node?.key ?? null,
      this.isSSR
    );
    if (!this.isSSR) {
      this.collection = this.nextCollection;
      this.nextCollection = null;
    }
  }
}

const BUILDING_BLOCK_mountDependencies: MountDependencies = (
  buildingBlocks,
  store,
  atom,
) => {
  const mountedMap = buildingBlocks[1]
  const changedAtoms = buildingBlocks[3]
  const storeHooks = buildingBlocks[6]
  const ensureAtomState = buildingBlocks[11]
  const invalidateDependents = buildingBlocks[15]
  const mountAtom = buildingBlocks[18]
  const unmountAtom = buildingBlocks[19]
  const atomState = ensureAtomState(buildingBlocks, store, atom)
  const mounted = mountedMap.get(atom)
  if (mounted && atomState.d.size > 0) {
    for (const [a, n] of atomState.d) {
      if (!mounted.d.has(a)) {
        const aState = ensureAtomState(buildingBlocks, store, a)
        const aMounted = mountAtom(buildingBlocks, store, a)
        aMounted.t.add(atom)
        mounted.d.add(a)
        if (n !== aState.n) {
          changedAtoms.add(a)
          invalidateDependents(buildingBlocks, store, a)
          storeHooks.c?.(a)
        }
      }
    }
    for (const a of mounted.d) {
      if (!atomState.d.has(a)) {
        mounted.d.delete(a)
        const aMounted = unmountAtom(buildingBlocks, store, a)
        aMounted?.t.delete(atom)
      }
    }
  }
}

const BUILDING_BLOCK_unmountAtom: UnmountAtom = (
  buildingBlocks,
  store,
  atom,
) => {
  const mountedMap = buildingBlocks[1]
  const unmountCallbacks = buildingBlocks[5]
  const storeHooks = buildingBlocks[6]
  const ensureAtomState = buildingBlocks[11]
  const unmountAtom = buildingBlocks[19]
  const atomState = ensureAtomState(buildingBlocks, store, atom)
  let mounted = mountedMap.get(atom)
  if (!mounted || mounted.l.size) {
    return mounted
  }
  let isDependent = false
  for (const a of mounted.t) {
    if (mountedMap.get(a)?.d.has(atom)) {
      isDependent = true
      break
    }
  }
  if (!isDependent) {
    // unmount self
    if (mounted.u) {
      unmountCallbacks.add(mounted.u)
    }
    mounted = undefined
    mountedMap.delete(atom)
    // unmount dependencies
    for (const a of atomState.d.keys()) {
      const aMounted = unmountAtom(buildingBlocks, store, a)
      aMounted?.t.delete(atom)
    }
    storeHooks.u?.(atom)
    return undefined
  }
  return mounted
}

const use =
  React.use ||
  // This extra generic is to avoid TypeScript mixing up the generic and JSX sytax
  // and emitting an error.
  // We assume that this is only for the `use(thenable)` case, not `use(context)`.
  // https://github.com/facebook/react/blob/aed00dacfb79d17c53218404c52b1c7aa59c4a89/packages/react-server/src/ReactFizzThenable.js#L45
  (<T, _>(
    thenable: Promise<T> & {
      status?: 'pending' | 'fulfilled' | 'rejected'
      value?: T
      reason?: unknown
    }
  ): T => {
    switch (thenable.status) {
      case 'pending':
        throw thenable
      case 'fulfilled':
        return thenable.value as T
      case 'rejected':
        throw thenable.reason
      default:
        thenable.status = 'pending'
        thenable.then(
          v => {
            thenable.status = 'fulfilled'
            thenable.value = v
          },
          e => {
            thenable.status = 'rejected'
            thenable.reason = e
          }
        )
        throw thenable
    }
  })

onFocus(e: FocusEvent): void {
  let activateButton = this.getCurrentActivateButton();
  let eventTarget = getEventTarget(e);
  if (eventTarget === activateButton) {
    // TODO: canceling this breaks the focus ring. Revisit when we support tabbing.
    this.cancelEvent(e);
    return;
  }

  // Prevent focus events, except to the original drag target.
  if (eventTarget !== this.dragTarget.element) {
    this.cancelEvent(e);
  }

  // Ignore focus events on the window/document (JSDOM). Will be handled in onBlur, below.
  if (!(eventTarget instanceof HTMLElement) || eventTarget === this.dragTarget.element) {
    return;
  }

  let dropTarget =
    this.validDropTargets.find(target => target.element === eventTarget) ||
    this.validDropTargets.find(target => nodeContains(target.element, eventTarget));

  if (!dropTarget) {
    // if (e.target === activateButton) {
    //   activateButton.focus();
    // }
    if (this.currentDropTarget) {
      this.currentDropTarget.element.focus();
    } else {
      this.dragTarget.element.focus();
    }
    return;
  }

  let item = dropItems.get(eventTarget);
  if (dropTarget) {
    this.setCurrentDropTarget(dropTarget, item);
  }
}

onClick(e: MouseEvent): void {
  this.cancelEvent(e);
  if (isVirtualClick(e) || this.isVirtualClick) {
    let dropElements = dropItems.values();
    let eventTarget = getEventTarget(e) as HTMLElement;
    let item = [...dropElements].find(
      item =>
        item.element === eventTarget || nodeContains(item.activateButtonRef?.current, eventTarget)
    );
    let dropTarget = this.validDropTargets.find(target =>
      nodeContains(target.element, eventTarget)
    );
    let activateButton =
      item?.activateButtonRef?.current ?? dropTarget?.activateButtonRef?.current;
    if (nodeContains(activateButton, eventTarget) && dropTarget) {
      this.activate(dropTarget, item);
      return;
    }

    if (getEventTarget(e) === this.dragTarget.element) {
      this.cancel();
      return;
    }

    if (dropTarget) {
      this.setCurrentDropTarget(dropTarget, item);
      this.drop(item);
    }
  }
}

import type { Dict } from '../types';
import { warnOnce } from './warnOnce';

export const LIMIT = 200;

export default (displayName: string, componentId: string) => {
  let generatedClasses: Dict<any> = {};
  let warningSeen = false;

  return (className: string) => {
    if (!warningSeen) {
      generatedClasses[className] = true;
      if (Object.keys(generatedClasses).length >= LIMIT) {
        const parsedIdString = componentId ? ` with the id of "${componentId}"` : '';
        warnOnce(
          'too-many-classes',
          `over ${LIMIT} classes were generated for component ${displayName}${parsedIdString}.
Consider using the attrs method, together with a style object for frequently changed styles.
Example:
  const Component = styled.div.attrs(props => ({
    style: {
      background: props.background,
    },
  }))\`width: 100%;\`

  <Component />`,
          componentId
        );
        warningSeen = true;
        generatedClasses = {};
      }
    }
  };
};

public set currentNode(node: Node) {
  if (!nodeContains(this.root, node)) {
    throw new Error('Cannot set currentNode to a node that is not contained by the root node.');
  }

  const walkers: TreeWalker[] = [];
  let curNode: Node | null | undefined = node;
  let currentWalkerCurrentNode = node;

  this._currentNode = node;

  while (curNode && curNode !== this.root) {
    if (curNode.nodeType === Node.DOCUMENT_FRAGMENT_NODE) {
      const shadowRoot = curNode as ShadowRoot;

      const walker = this._doc.createTreeWalker(shadowRoot, this.whatToShow, {
        acceptNode: this._acceptNode
      });

      walkers.push(walker);

      walker.currentNode = currentWalkerCurrentNode;

      this._currentSetFor.add(walker);

      curNode = currentWalkerCurrentNode = shadowRoot.host;
    } else {
      curNode = curNode.parentNode;
    }
  }

  const walker = this._doc.createTreeWalker(this.root, this.whatToShow, {
    acceptNode: this._acceptNode
  });

  walkers.push(walker);

  walker.currentNode = currentWalkerCurrentNode;

  this._currentSetFor.add(walker);

  this._walkerStack = walkers;
}

if (isFunction(styles)) {
    // Treat function input as a block-level interpolation.
    const slots = [styles as StyleFunction<Props>, ...interpolations];
    const synthesizedStrings: string[] = new Array(slots.length + 1).fill('');
    const rules = flattenStructure<Interpolation<NoInfer<Props>>>(
      interleave<Props>(synthesizedStrings, slots) as ReadonlyArray<unknown>
    );
    attachSourceInputs(rules, synthesizedStrings, slots);
    return rules as RuleSet<NoInfer<Props>>;
  }

  const styleStringArray = styles as TemplateStringsArray;

  if (
    interpolations.length === 0 &&
    styleStringArray.length === 1 &&
    typeof styleStringArray[0] === 'string'
  ) {
    // Pure-static templates (no interpolations): skip flattenStructure
    // while still attaching Source metadata for `${staticMixin}` reuse.
    const rules: Interpolation<NoInfer<Props>>[] = [
      styleStringArray[0] as Interpolation<NoInfer<Props>>,
    ];
    attachSourceInputs(rules, styleStringArray, interpolations);
    return rules as RuleSet<NoInfer<Props>>;
  }

  const rules = flattenStructure<Interpolation<NoInfer<Props>>>(
    interleave<Props>(styleStringArray, interpolations) as ReadonlyArray<unknown>
  );
  attachSourceInputs(rules, styleStringArray, interpolations);

function interleaveWithSentinels(
  strings: ReadonlyArray<string>,
  interpolations: ReadonlyArray<unknown>
): string {
  const count = interpolations.length;
  if (count === 0) return strings.length > 0 ? strings[0] : '';

  let prevWasStandalone = true; // start of input is a statement boundary
  let out = strings[0] || '';
  for (let i = 0; i < count; i++) {
    const prefix = strings[i] || '';
    const suffix = strings[i + 1] || '';
    let standalone = isStandaloneSlot(prefix, suffix, prevWasStandalone);
    if (!standalone && shouldRecoverFragmentSlot(prefix, interpolations[i])) {
      // User forgot a `;` before what is clearly a block-style fragment
      // (its source carries top-level `;`/`{`/`}`). Inject the missing
      // terminator and promote the slot to standalone so the pending
      // decl closes instead of swallowing the fragment as part of its
      // value. Value-position fragments (prefix ends in `:`, `,`, `(`,
      // `/`) are out of scope.
      out += ';';
      standalone = true;
    }
    out += standalone ? '\0J' : '\0I';
    out += i;
    out += '\0';
    out += suffix;
    prevWasStandalone = standalone;
  }
  return out;
}

next(): void {
  // TODO: Allow tabbing to the activate button. Revisit once we fix the focus ring.
  // For now, the activate button is reachable by screen readers and ArrowLeft/ArrowRight
  // is usable specifically by Tree. Will need tabbing for other components.
  // let activateButton = this.getCurrentActivateButton();
  // if (activateButton && document.activeElement !== activateButton) {
  //   activateButton.focus();
  //   return;
  // }

  if (!this.currentDropTarget) {
    this.setCurrentDropTarget(this.validDropTargets[0]);
    return;
  }

  let index = this.validDropTargets.indexOf(this.currentDropTarget);
  if (index < 0) {
    this.setCurrentDropTarget(this.validDropTargets[0]);
    return;
  }

  // If we've reached the end of the valid drop targets, cycle back to the original drag target.
  // This lets the user cancel the drag in case they don't have an Escape key (e.g. iPad keyboard case).
  if (index === this.validDropTargets.length - 1) {
    if (!this.dragTarget.element.closest('[aria-hidden="true"], [inert]')) {
      this.setCurrentDropTarget(null);
      this.dragTarget.element.focus();
    } else {
      this.setCurrentDropTarget(this.validDropTargets[0]);
    }
  } else {
    this.setCurrentDropTarget(this.validDropTargets[index + 1]);
  }
}
